import React, { useCallback, useEffect, useId, useMemo, useRef, useState } from 'react';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn, useControllable } from '@ds0/primitives';
import {
    AccordionContext,
    AccordionItemContext,
    useAccordionContext,
    useAccordionItemContext,
} from '@ds0/primitives';
import type {
    AccordionProps,
    AccordionItemProps,
    AccordionTriggerProps,
    AccordionContentProps,
} from '@ds0/primitives';

// ─── Chevron SVG ─────────────────────────────────────────────

function ChevronDown({ className }: { className?: string }): React.JSX.Element {
    return (
        <svg
            xmlns="http://www.w3.org/2000/svg"
            width="16"
            height="16"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
            className={className}
            aria-hidden="true"
        >
            <path d="m6 9 6 6 6-6" />
        </svg>
    );
}

// ─── Variants ────────────────────────────────────────────────

const accordionTriggerVariants = cva(
    'flex flex-1 items-center justify-between py-4 font-medium transition-all hover:underline [&[data-state=open]>svg]:rotate-180',
    {},
);

const accordionContentVariants = cva(
    'overflow-hidden text-sm transition-all data-[state=closed]:animate-accordion-up data-[state=open]:animate-accordion-down',
    {},
);

// ─── Root ─────────────────────────────────────────────────────

/**
 * Styled Accordion component.
 * A vertically stacked set of collapsible sections.
 *
 * @example
 * ```tsx
 * <Accordion type="single" defaultValue="item-1">
 *   <Accordion.Item value="item-1">
 *     <Accordion.Trigger>Section 1</Accordion.Trigger>
 *     <Accordion.Content>Content 1</Accordion.Content>
 *   </Accordion.Item>
 * </Accordion>
 * ```
 *
 * @see {@link https://ds0.systems/docs/components/accordion | Documentation}
 */
function Accordion({
    type = 'single',
    value,
    defaultValue,
    onValueChange,
    collapsible = true,
    isDisabled = false,
    children,
    className,
    ...props
}: AccordionProps): React.JSX.Element {
    const normalizeValue = (v: string | string[] | undefined): string[] => {
        if (v === undefined) return [];
        return Array.isArray(v) ? v : [v];
    };

    const isControlled = value !== undefined;
    const [internalValues, setInternalValues] = useState<string[]>(
        normalizeValue(defaultValue),
    );
    const expandedValues = isControlled ? normalizeValue(value) : internalValues;

    const toggleItem = useCallback(
        (itemValue: string) => {
            let nextValues: string[];
            if (type === 'single') {
                const isExpanded = expandedValues.includes(itemValue);
                if (isExpanded && collapsible) {
                    nextValues = [];
                } else if (isExpanded && !collapsible) {
                    return;
                } else {
                    nextValues = [itemValue];
                }
            } else {
                const isExpanded = expandedValues.includes(itemValue);
                nextValues = isExpanded
                    ? expandedValues.filter((v) => v !== itemValue)
                    : [...expandedValues, itemValue];
            }

            if (!isControlled) {
                setInternalValues(nextValues);
            }
            if (onValueChange) {
                onValueChange(type === 'single' ? (nextValues[0] ?? '') : nextValues);
            }
        },
        [type, expandedValues, collapsible, isControlled, onValueChange],
    );

    const contextValue = useMemo(
        () => ({ expandedValues, toggleItem, isDisabled }),
        [expandedValues, toggleItem, isDisabled],
    );

    return (
        <AccordionContext.Provider value={contextValue}>
            <div className={className} {...props}>
                {children}
            </div>
        </AccordionContext.Provider>
    );
}

Accordion.displayName = 'Accordion';

// ─── Item ─────────────────────────────────────────────────────

function AccordionItem({
    value,
    isDisabled: itemDisabled = false,
    children,
    className,
    ...props
}: AccordionItemProps): React.JSX.Element {
    const ctx = useAccordionContext();
    const baseId = useId();
    const isExpanded = ctx.expandedValues.includes(value);
    const isDisabled = ctx.isDisabled || itemDisabled;

    const itemContextValue = useMemo(
        () => ({
            value,
            isExpanded,
            isDisabled,
            triggerId: `${baseId}-trigger`,
            contentId: `${baseId}-content`,
        }),
        [value, isExpanded, isDisabled, baseId],
    );

    return (
        <AccordionItemContext.Provider value={itemContextValue}>
            <div
                data-state={isExpanded ? 'open' : 'closed'}
                data-disabled={isDisabled || undefined}
                className={cn('border-b', className)}
                {...props}
            >
                {children}
            </div>
        </AccordionItemContext.Provider>
    );
}

AccordionItem.displayName = 'AccordionItem';

// ─── Trigger ──────────────────────────────────────────────────

const AccordionTrigger = React.forwardRef<HTMLButtonElement, AccordionTriggerProps>(
    ({ children, className, onClick, ...props }, ref) => {
        const ctx = useAccordionContext();
        const item = useAccordionItemContext();

        return (
            <h3 className="flex">
                <button
                    ref={ref}
                    type="button"
                    id={item.triggerId}
                    aria-expanded={item.isExpanded}
                    aria-controls={item.contentId}
                    aria-disabled={item.isDisabled || undefined}
                    data-state={item.isExpanded ? 'open' : 'closed'}
                    data-disabled={item.isDisabled || undefined}
                    className={cn(accordionTriggerVariants(), className)}
                    onClick={(event) => {
                        onClick?.(event);
                        if (!event.defaultPrevented && !item.isDisabled) {
                            ctx.toggleItem(item.value);
                        }
                    }}
                    {...props}
                >
                    {children}
                    <ChevronDown className="h-4 w-4 shrink-0 transition-transform duration-200" />
                </button>
            </h3>
        );
    },
);

AccordionTrigger.displayName = 'AccordionTrigger';

// ─── Content ──────────────────────────────────────────────────

const AccordionContent = React.forwardRef<HTMLDivElement, AccordionContentProps>(
    ({ forceMount = false, children, className, ...props }, ref) => {
        const item = useAccordionItemContext();
        const contentRef = useRef<HTMLDivElement>(null);

        useEffect(() => {
            const content = contentRef.current;
            if (!content) return;
            const height = content.scrollHeight;
            content.style.setProperty('--ds0-accordion-content-height', `${height}px`);
        });

        if (!item.isExpanded && !forceMount) return null;

        return (
            <div
                ref={(node) => {
                    (contentRef as React.MutableRefObject<HTMLDivElement | null>).current = node;
                    if (typeof ref === 'function') ref(node);
                    else if (ref) (ref as React.MutableRefObject<HTMLDivElement | null>).current = node;
                }}
                id={item.contentId}
                role="region"
                aria-labelledby={item.triggerId}
                data-state={item.isExpanded ? 'open' : 'closed'}
                hidden={!item.isExpanded}
                className={cn(accordionContentVariants(), className)}
                {...props}
            >
                <div className="pb-4 pt-0">{children}</div>
            </div>
        );
    },
);

AccordionContent.displayName = 'AccordionContent';

// ─── Compound Export ─────────────────────────────────────────

const AccordionCompound = Object.assign(Accordion, {
    Item: AccordionItem,
    Trigger: AccordionTrigger,
    Content: AccordionContent,
});

export {
    AccordionCompound as Accordion,
    AccordionItem,
    AccordionTrigger,
    AccordionContent,
    accordionTriggerVariants,
    accordionContentVariants,
};

import React, { forwardRef, useState, useCallback } from 'react';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '@ds0/primitives';
import type { AlertProps, AlertTitleProps, AlertDescriptionProps } from '@ds0/primitives';

// ─── Variant Icons (Inline SVG) ──────────────────────────────

function InfoIcon(): React.JSX.Element {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <circle cx="12" cy="12" r="10" /><path d="M12 16v-4" /><path d="M12 8h.01" />
        </svg>
    );
}

function SuccessIcon(): React.JSX.Element {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <circle cx="12" cy="12" r="10" /><path d="m9 12 2 2 4-4" />
        </svg>
    );
}

function WarningIcon(): React.JSX.Element {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z" /><path d="M12 9v4" /><path d="M12 17h.01" />
        </svg>
    );
}

function DestructiveIcon(): React.JSX.Element {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <circle cx="12" cy="12" r="10" /><path d="m15 9-6 6" /><path d="m9 9 6 6" />
        </svg>
    );
}

function CloseIcon(): React.JSX.Element {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <path d="M18 6 6 18" /><path d="m6 6 12 12" />
        </svg>
    );
}

const variantIcons: Record<string, React.FC> = {
    info: InfoIcon,
    success: SuccessIcon,
    warning: WarningIcon,
    destructive: DestructiveIcon,
};

// ─── Variants ────────────────────────────────────────────────

const alertVariants = cva(
    'relative w-full rounded-lg border p-4 [&>svg~*]:pl-7 [&>svg+div]:translate-y-[-3px] [&>svg]:absolute [&>svg]:left-4 [&>svg]:top-4 [&>svg]:text-foreground',
    {
        variants: {
            variant: {
                default: 'bg-background text-foreground',
                info: 'border-blue-200 bg-blue-50 text-blue-900 dark:border-blue-800 dark:bg-blue-950 dark:text-blue-100 [&>svg]:text-blue-600',
                success: 'border-green-200 bg-green-50 text-green-900 dark:border-green-800 dark:bg-green-950 dark:text-green-100 [&>svg]:text-green-600',
                warning: 'border-yellow-200 bg-yellow-50 text-yellow-900 dark:border-yellow-800 dark:bg-yellow-950 dark:text-yellow-100 [&>svg]:text-yellow-600',
                destructive: 'border-destructive/50 text-destructive dark:border-destructive [&>svg]:text-destructive',
            },
        },
        defaultVariants: {
            variant: 'default',
        },
    },
);

// ─── Root ─────────────────────────────────────────────────────

/**
 * Styled Alert component.
 * A non-modal message for communicating status, warnings, or errors.
 *
 * @example
 * ```tsx
 * <Alert variant="info">
 *   <Alert.Title>Heads up!</Alert.Title>
 *   <Alert.Description>You can add components to your app using the CLI.</Alert.Description>
 * </Alert>
 * ```
 *
 * @see {@link https://ds0.systems/docs/components/alert | Documentation}
 */
const Alert = forwardRef<HTMLDivElement, AlertProps>(
    ({ variant = 'default', isDismissible = false, onDismiss, children, className, ...props }, ref) => {
        const [isDismissed, setIsDismissed] = useState(false);

        const handleDismiss = useCallback(() => {
            setIsDismissed(true);
            onDismiss?.();
        }, [onDismiss]);

        if (isDismissed) return null;

        const Icon = variantIcons[variant];

        return (
            <div
                ref={ref}
                role="alert"
                data-variant={variant}
                className={cn(alertVariants({ variant }), className)}
                {...props}
            >
                {Icon && <Icon />}
                {children}
                {isDismissible && (
                    <button
                        type="button"
                        aria-label="Dismiss alert"
                        className="absolute right-2 top-2 rounded-md p-1 opacity-70 transition-opacity hover:opacity-100 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring"
                        onClick={handleDismiss}
                    >
                        <CloseIcon />
                    </button>
                )}
            </div>
        );
    },
);

Alert.displayName = 'Alert';

// ─── Title ───────────────────────────────────────────────────

const AlertTitle = forwardRef<HTMLHeadingElement, AlertTitleProps>(
    ({ children, className, ...props }, ref) => (
        <h5
            ref={ref}
            className={cn('mb-1 font-medium leading-none tracking-tight', className)}
            {...props}
        >
            {children}
        </h5>
    ),
);

AlertTitle.displayName = 'AlertTitle';

// ─── Description ─────────────────────────────────────────────

const AlertDescription = forwardRef<HTMLParagraphElement, AlertDescriptionProps>(
    ({ children, className, ...props }, ref) => (
        <div
            ref={ref}
            className={cn('text-sm [&_p]:leading-relaxed', className)}
            {...props}
        >
            {children}
        </div>
    ),
);

AlertDescription.displayName = 'AlertDescription';

// ─── Compound Export ─────────────────────────────────────────

const AlertCompound = Object.assign(Alert, {
    Title: AlertTitle,
    Description: AlertDescription,
});

export { AlertCompound as Alert, AlertTitle, AlertDescription, alertVariants };

import React, { forwardRef } from 'react';
import { cn } from '@ds0/primitives';
import { useAspectRatio } from '@ds0/primitives';
import type { StyledAspectRatioProps } from '@ds0/primitives';

const AspectRatio = forwardRef<HTMLDivElement, StyledAspectRatioProps>(
    ({ ratio = 1, children, className, style, ...props }, ref) => {
        const { containerStyle, innerStyle } = useAspectRatio(ratio);
        return (
            <div ref={ref} className={cn('overflow-hidden', className)} style={{ ...containerStyle, ...style }} {...props}>
                <div style={innerStyle} className="flex items-center justify-center">{children}</div>
            </div>
        );
    },
);

AspectRatio.displayName = 'AspectRatio';
export { AspectRatio };
export type { StyledAspectRatioProps as AspectRatioProps };

import React, { forwardRef } from 'react';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@ds0/primitives';
import { useAvatar } from '@ds0/primitives';
import type { StyledAvatarProps } from '@ds0/primitives';

const avatarVariants = cva(
    'relative inline-flex shrink-0 items-center justify-center overflow-hidden bg-muted font-medium',
    {
        variants: {
            size: { xs: 'h-6 w-6 text-xs', sm: 'h-8 w-8 text-xs', md: 'h-10 w-10 text-sm', lg: 'h-12 w-12 text-base', xl: 'h-16 w-16 text-lg' },
            shape: { circle: 'rounded-full', square: 'rounded-md' },
        },
        defaultVariants: { size: 'md', shape: 'circle' },
    },
);

type AvatarVariantProps = VariantProps<typeof avatarVariants>;
interface AvatarProps extends StyledAvatarProps, AvatarVariantProps { }

const Avatar = forwardRef<HTMLDivElement, AvatarProps>(
    ({ className, size, shape, src, alt, fallback, ...props }, ref) => {
        const { imageProps, imageState } = useAvatar({ src, alt });

        const renderFallback = () => {
            if (typeof fallback === 'string') return <span className="select-none" aria-hidden="true">{fallback.slice(0, 2).toUpperCase()}</span>;
            return fallback ?? <span className="select-none" aria-hidden="true">{alt?.slice(0, 2).toUpperCase()}</span>;
        };

        return (
            <div ref={ref} className={cn(avatarVariants({ size, shape }), className)} role={imageState !== 'loaded' ? 'img' : undefined} aria-label={imageState !== 'loaded' ? alt : undefined} {...props}>
                {imageState === 'loaded' ? <img className="h-full w-full object-cover" {...imageProps} /> : renderFallback()}
            </div>
        );
    },
);

Avatar.displayName = 'Avatar';
export { Avatar, avatarVariants };
export type { AvatarProps };

import React, { forwardRef } from 'react';
import { cva, type VariantProps } from 'class-variance-authority';
import { cn } from '@ds0/primitives';
import type { StyledBadgeProps } from '@ds0/primitives';

const badgeVariants = cva(
    'inline-flex items-center rounded-full font-medium transition-colors',
    {
        variants: {
            variant: {
                default: 'bg-primary text-primary-foreground',
                secondary: 'bg-secondary text-secondary-foreground',
                destructive: 'bg-destructive text-destructive-foreground',
                success: 'bg-success text-success-foreground',
                warning: 'bg-warning text-warning-foreground',
                outline: 'border border-border text-foreground',
            },
            size: {
                sm: 'px-2 py-0.5 text-xs',
                md: 'px-2.5 py-0.5 text-xs',
            },
        },
        defaultVariants: { variant: 'default', size: 'md' },
    },
);

type BadgeVariants = VariantProps<typeof badgeVariants>;
interface BadgeProps extends StyledBadgeProps, BadgeVariants {}

const Badge = forwardRef<HTMLSpanElement, BadgeProps>(
    ({ className, variant, size, children, ...props }, ref) => (
        <span ref={ref} className={cn(badgeVariants({ variant, size }), className)} {...props}>
            {children}
        </span>
    ),
);
Badge.displayName = 'Badge';
export { Badge, badgeVariants };
export type { BadgeProps };

import React, { forwardRef } from 'react';

import { cn } from '@ds0/primitives';
import type {
    BreadcrumbProps,
    BreadcrumbListProps,
    BreadcrumbItemProps,
    BreadcrumbLinkProps,
    BreadcrumbPageProps,
    BreadcrumbSeparatorProps,
    BreadcrumbEllipsisProps,
} from '@ds0/primitives';

// ─── Icons ───────────────────────────────────────────────────

const ChevronRight = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
        <path d="m9 18 6-6-6-6" />
    </svg>
);

const MoreHorizontal = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
        <circle cx="12" cy="12" r="1" /><circle cx="19" cy="12" r="1" /><circle cx="5" cy="12" r="1" />
    </svg>
);

// ─── Root ─────────────────────────────────────────────────────

/**
 * Styled Breadcrumb component.
 * Shows the user's current location within a navigational hierarchy.
 *
 * @example
 * ```tsx
 * <Breadcrumb>
 *   <Breadcrumb.List>
 *     <Breadcrumb.Item>
 *       <Breadcrumb.Link href="/">Home</Breadcrumb.Link>
 *     </Breadcrumb.Item>
 *     <Breadcrumb.Separator />
 *     <Breadcrumb.Item>
 *       <Breadcrumb.Page>Current</Breadcrumb.Page>
 *     </Breadcrumb.Item>
 *   </Breadcrumb.List>
 * </Breadcrumb>
 * ```
 *
 * @see {@link https://ds0.systems/docs/components/breadcrumb | Documentation}
 */
const BreadcrumbRoot = forwardRef<HTMLElement, BreadcrumbProps>(
    ({ children, className, ...props }, ref) => (
        <nav ref={ref} aria-label={props['aria-label'] || 'Breadcrumb'} className={className} {...props}>
            {children}
        </nav>
    ),
);

BreadcrumbRoot.displayName = 'Breadcrumb';

// ─── List ─────────────────────────────────────────────────────

const BreadcrumbList = forwardRef<HTMLOListElement, BreadcrumbListProps>(
    ({ children, className, ...props }, ref) => (
        <ol
            ref={ref}
            className={cn(
                'flex flex-wrap items-center gap-1.5 break-words text-sm text-muted-foreground sm:gap-2.5',
                className,
            )}
            {...props}
        >
            {children}
        </ol>
    ),
);

BreadcrumbList.displayName = 'BreadcrumbList';

// ─── Item ─────────────────────────────────────────────────────

const BreadcrumbItem = forwardRef<HTMLLIElement, BreadcrumbItemProps>(
    ({ children, className, ...props }, ref) => (
        <li
            ref={ref}
            className={cn('inline-flex items-center gap-1.5', className)}
            {...props}
        >
            {children}
        </li>
    ),
);

BreadcrumbItem.displayName = 'BreadcrumbItem';

// ─── Link ─────────────────────────────────────────────────────

const BreadcrumbLink = forwardRef<HTMLAnchorElement, BreadcrumbLinkProps>(
    ({ children, className, ...props }, ref) => (
        <a
            ref={ref}
            className={cn('transition-colors hover:text-foreground', className)}
            {...props}
        >
            {children}
        </a>
    ),
);

BreadcrumbLink.displayName = 'BreadcrumbLink';

// ─── Page (current) ──────────────────────────────────────────

const BreadcrumbPage = forwardRef<HTMLSpanElement, BreadcrumbPageProps>(
    ({ children, className, ...props }, ref) => (
        <span
            ref={ref}
            aria-current="page"
            className={cn('font-normal text-foreground', className)}
            {...props}
        >
            {children}
        </span>
    ),
);

BreadcrumbPage.displayName = 'BreadcrumbPage';

// ─── Separator ───────────────────────────────────────────────

const BreadcrumbSeparator = forwardRef<HTMLLIElement, BreadcrumbSeparatorProps>(
    ({ children, className, ...props }, ref) => (
        <li
            ref={ref}
            role="presentation"
            aria-hidden="true"
            className={cn('[&>svg]:size-3.5', className)}
            {...props}
        >
            {children || <ChevronRight />}
        </li>
    ),
);

BreadcrumbSeparator.displayName = 'BreadcrumbSeparator';

// ─── Ellipsis ────────────────────────────────────────────────

const BreadcrumbEllipsis = forwardRef<HTMLSpanElement, BreadcrumbEllipsisProps>(
    ({ className, ...props }, ref) => (
        <span
            ref={ref}
            aria-hidden="true"
            className={cn('flex h-9 w-9 items-center justify-center', className)}
            {...props}
        >
            <MoreHorizontal />
        </span>
    ),
);

BreadcrumbEllipsis.displayName = 'BreadcrumbEllipsis';

// ─── Compound Export ─────────────────────────────────────────

const Breadcrumb = Object.assign(BreadcrumbRoot, {
    List: BreadcrumbList,
    Item: BreadcrumbItem,
    Link: BreadcrumbLink,
    Page: BreadcrumbPage,
    Separator: BreadcrumbSeparator,
    Ellipsis: BreadcrumbEllipsis,
});

export {
    Breadcrumb,
    BreadcrumbList,
    BreadcrumbItem,
    BreadcrumbLink,
    BreadcrumbPage,
    BreadcrumbSeparator,
    BreadcrumbEllipsis,
};

export {
    Breadcrumb,
    BreadcrumbList,
    BreadcrumbItem,
    BreadcrumbLink,
    BreadcrumbPage,
    BreadcrumbSeparator,
    BreadcrumbEllipsis,
} from './Breadcrumb';

import React, { forwardRef } from 'react';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '@ds0/primitives';
import { useButton } from '@ds0/primitives';
import type { StyledButtonProps } from '@ds0/primitives';

/**
 * Loading spinner component for the Button loading state.
 * Uses currentColor to inherit the button's text color.
 */
const Spinner = ({ className }: { className?: string }) => (
    <svg
        className={cn('animate-spin h-4 w-4', className)}
        xmlns="http://www.w3.org/2000/svg"
        fill="none"
        viewBox="0 0 24 24"
        aria-hidden="true"
    >
        <circle
            className="opacity-25"
            cx="12"
            cy="12"
            r="10"
            stroke="currentColor"
            strokeWidth="4"
        />
        <path
            className="opacity-75"
            fill="currentColor"
            d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
        />
    </svg>
);

const buttonVariants = cva(
    'inline-flex items-center justify-center gap-2 rounded-md font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2',
    {
        variants: {
            variant: {
                primary: 'bg-primary text-primary-foreground hover:bg-primary/90',
                secondary:
                    'bg-secondary text-secondary-foreground hover:bg-secondary/80',
                destructive:
                    'bg-destructive text-destructive-foreground hover:bg-destructive/90',
                ghost: 'hover:bg-accent hover:text-accent-foreground',
                outline:
                    'border border-input bg-background hover:bg-accent hover:text-accent-foreground',
            },
            size: {
                sm: 'h-8 px-3 text-xs gap-1.5',
                md: 'h-10 px-4 text-sm gap-2',
                lg: 'h-12 px-6 text-base gap-2',
            },
        },
        defaultVariants: {
            variant: 'primary',
            size: 'md',
        },
    },
);

type ButtonVariants = VariantProps<typeof buttonVariants>;

/**
 * Props for the styled Button component.
 */
interface ButtonProps extends StyledButtonProps, ButtonVariants { }

/**
 * Styled Button component.
 * Built on the headless ButtonPrimitive with Tailwind CSS styling via cva.
 *
 * @example
 * ```tsx
 * <Button variant="primary" size="md">
 *   Save Changes
 * </Button>
 * ```
 *
 * @example
 * ```tsx
 * <Button variant="destructive" leftIcon={<TrashIcon />}>
 *   Delete Account
 * </Button>
 * ```
 *
 * @see {@link https://ds0.systems/docs/components/button | Documentation}
 */
const Button = forwardRef<HTMLButtonElement, ButtonProps>(
    (
        {
            className,
            variant,
            size,
            isDisabled,
            isLoading,
            loadingText,
            leftIcon,
            rightIcon,
            children,
            ...props
        },
        ref,
    ) => {
        const { buttonProps } = useButton({
            isDisabled,
            isLoading,
            type: props.type,
            onClick: props.onClick,
            onKeyDown: props.onKeyDown,
            onKeyUp: props.onKeyUp,
        });

        return (
            <button
                ref={ref}
                className={cn(
                    buttonVariants({ variant, size }),
                    isDisabled && 'opacity-50 pointer-events-none',
                    isLoading && 'opacity-80 pointer-events-none',
                    className,
                )}
                {...props}
                {...buttonProps}
            >
                {isLoading && <Spinner />}
                {!isLoading && leftIcon}
                {isLoading && loadingText ? (
                    <span aria-live="polite">{loadingText}</span>
                ) : (
                    children
                )}
                {!isLoading && rightIcon}
            </button>
        );
    },
);

Button.displayName = 'Button';

export { Button, buttonVariants };
export type { ButtonProps };

