import React, { forwardRef, useCallback, useEffect, useMemo, useRef } from 'react';

import { cn, DrawerContext, useDrawerContext, useDrawer, Portal, useFocusTrap, useScrollLock, useEscapeKey } from '@ds0/primitives';
import type { DrawerProps, DrawerTriggerProps, DrawerContentProps, DrawerTitleProps, DrawerDescriptionProps, DrawerCloseProps } from '@ds0/primitives';

// ─── Root ─────────────────────────────────────────────────────

function Drawer({ open, defaultOpen, onOpenChange, side = 'right', children }: DrawerProps): React.JSX.Element {
    const drawer = useDrawer({ open, defaultOpen, onOpenChange });
    const triggerRef = useRef<HTMLButtonElement>(null);
    const contentRef = useRef<HTMLDivElement>(null);

    const contextValue = useMemo(() => ({
        isOpen: drawer.isOpen, open: drawer.open, close: drawer.close,
        side, ids: drawer.ids, triggerRef, contentRef,
    }), [drawer.isOpen, drawer.open, drawer.close, side, drawer.ids]);

    return <DrawerContext.Provider value={contextValue}>{children}</DrawerContext.Provider>;
}
Drawer.displayName = 'Drawer';

// ─── Trigger ──────────────────────────────────────────────────

const DrawerTrigger = forwardRef<HTMLButtonElement, DrawerTriggerProps>(
    ({ children, className, onClick, ...props }, ref) => {
        const { open, isOpen, ids, triggerRef } = useDrawerContext();
        return (
            <button
                ref={(node) => {
                    if (typeof ref === 'function') ref(node);
                    else if (ref) (ref as React.MutableRefObject<HTMLButtonElement | null>).current = node;
                    (triggerRef as React.MutableRefObject<HTMLButtonElement | null>).current = node;
                }}
                type="button" className={className} aria-haspopup="dialog" aria-expanded={isOpen}
                aria-controls={isOpen ? ids.content : undefined}
                onClick={(e) => { onClick?.(e); if (!e.defaultPrevented) open(); }}
                {...props}
            >{children}</button>
        );
    },
);
DrawerTrigger.displayName = 'DrawerTrigger';

// ─── Content ──────────────────────────────────────────────────

const sideClasses = {
    right: 'inset-y-0 right-0 h-full w-3/4 max-w-sm border-l data-[state=open]:slide-in-from-right data-[state=closed]:slide-out-to-right',
    left: 'inset-y-0 left-0 h-full w-3/4 max-w-sm border-r data-[state=open]:slide-in-from-left data-[state=closed]:slide-out-to-left',
    top: 'inset-x-0 top-0 w-full border-b data-[state=open]:slide-in-from-top data-[state=closed]:slide-out-to-top',
    bottom: 'inset-x-0 bottom-0 w-full border-t data-[state=open]:slide-in-from-bottom data-[state=closed]:slide-out-to-bottom',
} as const;

const DrawerContent = forwardRef<HTMLDivElement, DrawerContentProps>(
    ({ children, className, onEscapeKeyDown, ...props }, ref) => {
        const { isOpen, close, side, ids, triggerRef, contentRef } = useDrawerContext();

        useFocusTrap(contentRef, isOpen);
        useScrollLock(isOpen);

        const handleEscape = useCallback((event: KeyboardEvent) => {
            onEscapeKeyDown?.(event);
            if (!event.defaultPrevented) close();
        }, [onEscapeKeyDown, close]);
        useEscapeKey(handleEscape, isOpen);

        useEffect(() => {
            if (!isOpen && triggerRef.current) triggerRef.current.focus();
        }, [isOpen, triggerRef]);

        if (!isOpen) return null;

        return (
            <Portal>
                {/* Overlay */}
                <div
                    className="fixed inset-0 z-50 bg-black/80 data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0"
                    data-state={isOpen ? 'open' : 'closed'} aria-hidden="true" onClick={close}
                />
                {/* Panel */}
                <div
                    ref={(node) => {
                        if (typeof ref === 'function') ref(node);
                        else if (ref) (ref as React.MutableRefObject<HTMLDivElement | null>).current = node;
                        (contentRef as React.MutableRefObject<HTMLDivElement | null>).current = node;
                    }}
                    id={ids.content} role="dialog" aria-modal={true}
                    aria-labelledby={ids.title} aria-describedby={ids.description}
                    data-state={isOpen ? 'open' : 'closed'} data-side={side}
                    className={cn(
                        'fixed z-50 gap-4 bg-background p-6 shadow-lg transition ease-in-out duration-300',
                        'data-[state=open]:animate-in data-[state=closed]:animate-out',
                        sideClasses[side],
                        className,
                    )}
                    {...props}
                >{children}</div>
            </Portal>
        );
    },
);
DrawerContent.displayName = 'DrawerContent';

// ─── Title ────────────────────────────────────────────────────

const DrawerTitle = forwardRef<HTMLHeadingElement, DrawerTitleProps>(
    ({ children, className, ...props }, ref) => {
        const { ids } = useDrawerContext();
        return <h2 ref={ref} id={ids.title} className={cn('text-lg font-semibold leading-none tracking-tight', className)} {...props}>{children}</h2>;
    },
);
DrawerTitle.displayName = 'DrawerTitle';

// ─── Description ──────────────────────────────────────────────

const DrawerDescription = forwardRef<HTMLParagraphElement, DrawerDescriptionProps>(
    ({ children, className, ...props }, ref) => {
        const { ids } = useDrawerContext();
        return <p ref={ref} id={ids.description} className={cn('text-sm text-muted-foreground', className)} {...props}>{children}</p>;
    },
);
DrawerDescription.displayName = 'DrawerDescription';

// ─── Close ────────────────────────────────────────────────────

const DrawerClose = forwardRef<HTMLButtonElement, DrawerCloseProps>(
    ({ children, className, onClick, ...props }, ref) => {
        const { close } = useDrawerContext();
        return (
            <button ref={ref} type="button" className={cn('absolute right-4 top-4 rounded-sm opacity-70 hover:opacity-100', className)}
                onClick={(e) => { onClick?.(e); if (!e.defaultPrevented) close(); }}
                {...props}
            >{children}</button>
        );
    },
);
DrawerClose.displayName = 'DrawerClose';

// ─── Compound Export ──────────────────────────────────────────

const DrawerCompound = Object.assign(Drawer, {
    Trigger: DrawerTrigger, Content: DrawerContent,
    Title: DrawerTitle, Description: DrawerDescription, Close: DrawerClose,
});

export { DrawerCompound as Drawer, DrawerTrigger, DrawerContent, DrawerTitle, DrawerDescription, DrawerClose };

import React, { forwardRef, createContext, useContext, useId } from 'react';
import { cva } from 'class-variance-authority';

import { cn } from '@ds0/primitives';
import type {
    FormProps,
    FormFieldProps,
    FormLabelProps,
    FormDescriptionProps,
    FormErrorProps,
    FormSectionProps,
    FormActionsProps,
} from '@ds0/primitives';

// ─── Field Context ────────────────────────────────────────────

interface FieldContextValue {
    id: string;
    errorId: string;
    descriptionId: string;
    name: string;
    hasError: boolean;
    required: boolean;
}

const FieldContext = createContext<FieldContextValue | null>(null);
function useFieldContext(): FieldContextValue | null {
    return useContext(FieldContext);
}

// ─── Variants ────────────────────────────────────────────────

const formVariants = cva('space-y-6', {
    variants: {
        layout: {
            vertical: 'flex flex-col',
            horizontal: 'flex flex-col',
        },
    },
    defaultVariants: {
        layout: 'vertical',
    },
});

const formFieldVariants = cva('space-y-2', {
    variants: {
        layout: {
            vertical: 'flex flex-col',
            horizontal: 'flex flex-row items-start gap-4',
        },
    },
    defaultVariants: {
        layout: 'vertical',
    },
});

const formActionsVariants = cva('flex gap-3 pt-4', {
    variants: {
        align: {
            left: 'justify-start',
            center: 'justify-center',
            right: 'justify-end',
            apart: 'justify-between',
        },
    },
    defaultVariants: {
        align: 'right',
    },
});

// ─── Root ─────────────────────────────────────────────────────

/**
 * Styled Form component.
 * Provides layout structure and manages field composition.
 *
 * @example
 * ```tsx
 * <Form onSubmit={handleSubmit}>
 *   <Form.Field name="email" required>
 *     <Form.Label>Email</Form.Label>
 *     <Input type="email" />
 *     <Form.Error>Email is required</Form.Error>
 *   </Form.Field>
 *   <Form.Actions>
 *     <Button type="submit">Submit</Button>
 *   </Form.Actions>
 * </Form>
 * ```
 *
 * @see {@link https://ds0.systems/docs/components/form | Documentation}
 */
const FormRoot = forwardRef<HTMLFormElement, FormProps>(
    ({ children, layout = 'vertical', className, onSubmit, ...props }, ref) => (
        <form
            ref={ref}
            className={cn(formVariants({ layout }), className)}
            noValidate
            onSubmit={(e) => {
                e.preventDefault();
                onSubmit?.(e);
            }}
            {...props}
        >
            {children}
        </form>
    ),
);

FormRoot.displayName = 'Form';

// ─── Field ────────────────────────────────────────────────────

const FormField = forwardRef<HTMLDivElement, FormFieldProps>(
    ({ name, required = false, hasError = false, layout = 'vertical', children, className, ...props }, ref) => {
        const baseId = useId();
        const contextValue: FieldContextValue = {
            id: `${baseId}-${name}`,
            errorId: `${baseId}-${name}-error`,
            descriptionId: `${baseId}-${name}-desc`,
            name,
            hasError,
            required,
        };

        return (
            <FieldContext.Provider value={contextValue}>
                <div ref={ref} className={cn(formFieldVariants({ layout }), className)} role="group" {...props}>
                    {children}
                </div>
            </FieldContext.Provider>
        );
    },
);

FormField.displayName = 'FormField';

// ─── Label ────────────────────────────────────────────────────

const FormLabel = forwardRef<HTMLLabelElement, FormLabelProps>(
    ({ children, required, className, ...props }, ref) => {
        const field = useFieldContext();

        return (
            <label
                ref={ref}
                htmlFor={field?.id}
                className={cn('text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70', className)}
                {...props}
            >
                {children}
                {(required || field?.required) && (
                    <span className="text-destructive ml-1" aria-hidden="true">*</span>
                )}
            </label>
        );
    },
);

FormLabel.displayName = 'FormLabel';

// ─── Description ──────────────────────────────────────────────

const FormDescription = forwardRef<HTMLParagraphElement, FormDescriptionProps>(
    ({ children, className, ...props }, ref) => {
        const field = useFieldContext();

        return (
            <p ref={ref} id={field?.descriptionId} className={cn('text-sm text-muted-foreground', className)} {...props}>
                {children}
            </p>
        );
    },
);

FormDescription.displayName = 'FormDescription';

// ─── Error ────────────────────────────────────────────────────

const FormError = forwardRef<HTMLParagraphElement, FormErrorProps>(
    ({ children, className, ...props }, ref) => {
        const field = useFieldContext();

        return (
            <p ref={ref} id={field?.errorId} role="alert" className={cn('text-sm text-destructive font-medium', className)} {...props}>
                {children}
            </p>
        );
    },
);

FormError.displayName = 'FormError';

// ─── Section ──────────────────────────────────────────────────

const FormSection = forwardRef<HTMLFieldSetElement, FormSectionProps>(
    ({ title, description, children, className, ...props }, ref) => (
        <fieldset ref={ref} className={cn('space-y-4 border-none p-0', className)} {...props}>
            {title && <legend className="text-base font-semibold">{title}</legend>}
            {description && <p className="text-sm text-muted-foreground">{description}</p>}
            <div className="space-y-4">
                {children}
            </div>
        </fieldset>
    ),
);

FormSection.displayName = 'FormSection';

// ─── Actions ──────────────────────────────────────────────────

const FormActions = forwardRef<HTMLDivElement, FormActionsProps>(
    ({ align = 'right', children, className, ...props }, ref) => (
        <div ref={ref} className={cn(formActionsVariants({ align }), className)} role="group" {...props}>
            {children}
        </div>
    ),
);

FormActions.displayName = 'FormActions';

// ─── Compound Export ─────────────────────────────────────────

const Form = Object.assign(FormRoot, {
    Field: FormField,
    Label: FormLabel,
    Description: FormDescription,
    Error: FormError,
    Section: FormSection,
    Actions: FormActions,
});

export {
    Form,
    FormField,
    FormLabel,
    FormDescription,
    FormError,
    FormSection,
    FormActions,
    formVariants,
    formFieldVariants,
    formActionsVariants,
};

