                        {...props}
                        {...inputProps}
                    />

                    {rightIcon && (
                        <div className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground">
                            {rightIcon}
                        </div>
                    )}
                </div>

                {isInvalid && errorMessage ? (
                    <p
                        className="text-sm text-destructive"
                        {...errorMessageProps}
                    >
                        {errorMessage}
                    </p>
                ) : helperText ? (
                    <p
                        className="text-sm text-muted-foreground"
                        {...helperTextProps}
                    >
                        {helperText}
