import React, { forwardRef } from 'react';
import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '@ds0/primitives';
import { useToggle } from '@ds0/primitives';
import type { StyledToggleProps } from '@ds0/primitives';

const toggleVariants = cva(
    'inline-flex items-center justify-center rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 hover:bg-muted hover:text-muted-foreground data-[state=on]:bg-accent data-[state=on]:text-accent-foreground',
    {
        variants: {
            variant: {
                default: 'bg-transparent',
                outline:
                    'border border-input bg-transparent hover:bg-accent hover:text-accent-foreground',
            },
            size: {
                sm: 'h-8 px-2',
                md: 'h-10 px-3',
                lg: 'h-12 px-4',
            },
        },
        defaultVariants: {
            variant: 'default',
            size: 'md',
        },
    },
);

type ToggleVariants = VariantProps<typeof toggleVariants>;

/**
 * Styled Toggle component.
 * A two-state button that can be on or off, like a standalone toggle in a toolbar.
 *
 * @example
 * ```tsx
 * <Toggle aria-label="Toggle bold">
 *   <BoldIcon />
 * </Toggle>
 * ```
 *
 * @see {@link https://ds0.systems/docs/components/toggle | Documentation}
 */
const Toggle = forwardRef<HTMLButtonElement, StyledToggleProps & ToggleVariants>(
    ({ className, variant, size, pressed, defaultPressed, onPressedChange, isDisabled, children, ...props }, ref) => {
        const { toggleProps, isPressed } = useToggle({
            pressed,
            defaultPressed,
            onPressedChange,
            isDisabled,
        });

        return (
            <button
                ref={ref}
                className={cn(
                    toggleVariants({ variant, size }),
                    isDisabled && 'opacity-50 pointer-events-none',
                    className,
                )}
                {...props}
                {...toggleProps}
                data-state={isPressed ? 'on' : 'off'}
            >
                {children}
            </button>
        );
    },
);

Toggle.displayName = 'Toggle';

export { Toggle, toggleVariants };
export type { StyledToggleProps as ToggleProps };

import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { cva } from 'class-variance-authority';

import { cn } from '@ds0/primitives';
import { ToggleGroupContext, useToggleGroupContext } from '@ds0/primitives';
import type { ToggleGroupProps, ToggleGroupItemProps } from '@ds0/primitives';

// ─── Variants ────────────────────────────────────────────────

const toggleGroupVariants = cva(
    'inline-flex items-center rounded-md',
    {
        variants: {
            orientation: {
                horizontal: 'flex-row',
                vertical: 'flex-col',
            },
        },
        defaultVariants: {
            orientation: 'horizontal',
        },
    },
);

const toggleGroupItemVariants = cva(
    'inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 data-[state=on]:bg-accent data-[state=on]:text-accent-foreground',
    {
        variants: {
            variant: {
                default: 'bg-transparent hover:bg-muted hover:text-muted-foreground',
                outline: 'border border-input bg-transparent hover:bg-accent hover:text-accent-foreground',
            },
            size: {
                sm: 'h-8 px-2.5',
                md: 'h-10 px-3',
                lg: 'h-11 px-5',
            },
        },
        defaultVariants: {
            variant: 'default',
            size: 'md',
        },
    },
);

// ─── Root ─────────────────────────────────────────────────────

/**
 * Styled ToggleGroup component.
 * A set of two-state buttons where one or more can be toggled on.
 *
 * @example
 * ```tsx
 * <ToggleGroup type="single" defaultValue="center">
 *   <ToggleGroup.Item value="left">Left</ToggleGroup.Item>
 *   <ToggleGroup.Item value="center">Center</ToggleGroup.Item>
 *   <ToggleGroup.Item value="right">Right</ToggleGroup.Item>
 * </ToggleGroup>
 * ```
 *
 * @see {@link https://ds0.systems/docs/components/toggle-group | Documentation}
 */
function ToggleGroup({
    type = 'single',
    value,
    defaultValue,
    onValueChange,
    variant = 'default',
    size = 'md',
    orientation = 'horizontal',
    isDisabled = false,
    children,
    className,
    ...props
}: ToggleGroupProps): React.JSX.Element {
    const normalizeValue = (v: string | string[] | undefined): string[] => {
        if (v === undefined) return [];
        return Array.isArray(v) ? v : [v];
    };

    const isControlled = value !== undefined;
    const [internalValues, setInternalValues] = useState<string[]>(normalizeValue(defaultValue));
    const selectedValues = isControlled ? normalizeValue(value) : internalValues;

    const toggleItem = useCallback(
        (itemValue: string) => {
            let nextValues: string[];
            if (type === 'single') {
                const isSelected = selectedValues.includes(itemValue);
                nextValues = isSelected ? [] : [itemValue];
            } else {
                const isSelected = selectedValues.includes(itemValue);
                nextValues = isSelected
                    ? selectedValues.filter((v) => v !== itemValue)
                    : [...selectedValues, itemValue];
            }
            if (!isControlled) setInternalValues(nextValues);
            if (onValueChange) onValueChange(type === 'single' ? (nextValues[0] ?? '') : nextValues);
        },
        [type, selectedValues, isControlled, onValueChange],
    );

    const itemMapRef = useRef<Map<string, React.RefObject<HTMLButtonElement | null>>>(new Map());
    const registerItem = useCallback((v: string, ref: React.RefObject<HTMLButtonElement | null>) => {
        itemMapRef.current.set(v, ref);
    }, []);
    const unregisterItem = useCallback((v: string) => { itemMapRef.current.delete(v); }, []);
    const getItemEntries = useCallback(
        () => Array.from(itemMapRef.current.entries()).map(([v, ref]) => ({ value: v, ref })),
        [],
    );

    const contextValue = useMemo(
        () => ({
            selectedValues,
            toggleItem,
            isDisabled,
            variant,
            size,
            orientation,
            registerItem,
            unregisterItem,
            getItemEntries,
        }),
        [selectedValues, toggleItem, isDisabled, variant, size, orientation, registerItem, unregisterItem, getItemEntries],
    );

    return (
        <ToggleGroupContext.Provider value={contextValue}>
            <div
                role="group"
                data-orientation={orientation}
                className={cn(toggleGroupVariants({ orientation }), className)}
                {...props}
            >
                {children}
            </div>
        </ToggleGroupContext.Provider>
    );
}

ToggleGroup.displayName = 'ToggleGroup';

// ─── Item ─────────────────────────────────────────────────────

const ToggleGroupItem = React.forwardRef<HTMLButtonElement, ToggleGroupItemProps>(
    ({ value, isDisabled: itemDisabled = false, children, className, onClick, onKeyDown, ...props }, ref) => {
        const ctx = useToggleGroupContext();
        const isSelected = ctx.selectedValues.includes(value);
        const isDisabled = ctx.isDisabled || itemDisabled;
        const refObj = useRef<HTMLButtonElement | null>(null);

        useEffect(() => {
            ctx.registerItem(value, refObj);
            return () => ctx.unregisterItem(value);
        }, [value, ctx]);

        const handleKeyDown = useCallback(
            (event: React.KeyboardEvent<HTMLButtonElement>) => {
                onKeyDown?.(event);
                if (event.defaultPrevented || isDisabled) return;

                const entries = ctx.getItemEntries();
                const enabledEntries = entries.filter((e) => {
                    const el = e.ref.current;
                    return el && !el.disabled && el.getAttribute('aria-disabled') !== 'true';
                });
                const currentIndex = enabledEntries.findIndex((e) => e.value === value);
                const isHorizontal = ctx.orientation === 'horizontal';

                let nextIndex: number | undefined;

                switch (event.key) {
                    case isHorizontal ? 'ArrowRight' : 'ArrowDown':
                        event.preventDefault();
                        nextIndex = currentIndex + 1 >= enabledEntries.length ? 0 : currentIndex + 1;
                        break;
                    case isHorizontal ? 'ArrowLeft' : 'ArrowUp':
                        event.preventDefault();
                        nextIndex = currentIndex - 1 < 0 ? enabledEntries.length - 1 : currentIndex - 1;
                        break;
                    default:
                        return;
                }

                if (nextIndex !== undefined) {
                    enabledEntries[nextIndex]?.ref.current?.focus();
                }
            },
            [onKeyDown, isDisabled, ctx, value],
        );

        return (
            <button
                ref={(node) => {
                    refObj.current = node;
                    if (typeof ref === 'function') ref(node);
                    else if (ref) (ref as React.MutableRefObject<HTMLButtonElement | null>).current = node;
                }}
                type="button"
                role="radio"
                aria-checked={isSelected}
                aria-disabled={isDisabled || undefined}
                data-state={isSelected ? 'on' : 'off'}
                data-disabled={isDisabled || undefined}
                tabIndex={isSelected ? 0 : -1}
                className={cn(toggleGroupItemVariants({ variant: ctx.variant, size: ctx.size }), className)}
                onClick={(event) => {
                    onClick?.(event);
                    if (!event.defaultPrevented && !isDisabled) ctx.toggleItem(value);
                }}
                onKeyDown={handleKeyDown}
                {...props}
            >
                {children}
            </button>
        );
    },
);

ToggleGroupItem.displayName = 'ToggleGroupItem';

// ─── Compound Export ─────────────────────────────────────────

const ToggleGroupCompound = Object.assign(ToggleGroup, {
    Item: ToggleGroupItem,
});

export { ToggleGroupCompound as ToggleGroup, ToggleGroupItem, toggleGroupVariants, toggleGroupItemVariants };

import React, { forwardRef, useCallback, useMemo, useRef } from 'react';
import { cn, TooltipContext, useTooltipContext, useTooltip, Portal, useEscapeKey } from '@ds0/primitives';
import type { TooltipProps, TooltipTriggerProps, TooltipContentProps } from '@ds0/primitives';

function Tooltip({ open, defaultOpen, onOpenChange, delayDuration = 700, children }: TooltipProps): React.JSX.Element {
    const tip = useTooltip({ open, defaultOpen, onOpenChange });
    const triggerRef = useRef<HTMLElement>(null);
    const ctx = useMemo(() => ({ ...tip, triggerRef, delayDuration }), [tip, delayDuration]);
    return <TooltipContext.Provider value={ctx}>{children}</TooltipContext.Provider>;
}
Tooltip.displayName = 'Tooltip';

const TooltipTrigger = forwardRef<HTMLElement, TooltipTriggerProps>(
    ({ children, className, onMouseEnter, onMouseLeave, onFocus, onBlur, ...props }, ref) => {
        const { open, close, isOpen, ids, triggerRef, delayDuration } = useTooltipContext();
        const timerRef = useRef<ReturnType<typeof setTimeout>>(undefined);
        const handleOpen = useCallback(() => { clearTimeout(timerRef.current); timerRef.current = setTimeout(open, delayDuration); }, [open, delayDuration]);
        const handleClose = useCallback(() => { clearTimeout(timerRef.current); close(); }, [close]);
        return (
            <span
                ref={(node) => {
                    if (typeof ref === 'function') ref(node);
                    else if (ref) (ref as React.MutableRefObject<HTMLElement | null>).current = node;
                    (triggerRef as React.MutableRefObject<HTMLElement | null>).current = node;
                }}
                className={className} aria-describedby={isOpen ? ids.content : undefined}
                onMouseEnter={(e) => { onMouseEnter?.(e); handleOpen(); }}
                onMouseLeave={(e) => { onMouseLeave?.(e); handleClose(); }}
                onFocus={(e) => { onFocus?.(e); handleOpen(); }}
                onBlur={(e) => { onBlur?.(e); handleClose(); }}
                {...props}
            >{children}</span>
        );
    },
);
TooltipTrigger.displayName = 'TooltipTrigger';

const TooltipContent = forwardRef<HTMLDivElement, TooltipContentProps>(
    ({ children, className, side: _side, sideOffset: _offset, ...props }, ref) => {
        const { isOpen, close, ids } = useTooltipContext();
        const handleEscape = useCallback(() => close(), [close]);
        useEscapeKey(handleEscape, isOpen);
        if (!isOpen) return null;
        return (
            <Portal>
                <div
                    ref={ref} id={ids.content} role="tooltip" data-state={isOpen ? 'open' : 'closed'}
                    className={cn(
                        'z-50 overflow-hidden rounded-md border bg-popover px-3 py-1.5 text-sm text-popover-foreground shadow-md',
                        'animate-in fade-in-0 zoom-in-95',
                        className,
                    )}
                    {...props}
                >{children}</div>
            </Portal>
        );
    },
);
TooltipContent.displayName = 'TooltipContent';

const TooltipCompound = Object.assign(Tooltip, { Trigger: TooltipTrigger, Content: TooltipContent });
export { TooltipCompound as Tooltip, TooltipTrigger, TooltipContent };

import React, { useState } from 'react';

import { cn } from '@ds0/primitives';

import { Card } from '../../components/react/card';
import { Stack } from '../../components/react/stack';
import { Text } from '../../components/react/text';
