                            </Stack>

                            <Button type="submit" className="w-full" isLoading={isLoading}>
                                Sign in
                            </Button>
                        </Stack>
                    </form>
                </Stack>
            </Card.Content>

            {onSignUp && (
                <Card.Footer className="justify-center">
                    <Text size="sm" color="muted" as="span">
                        Don&apos;t have an account?{' '}
                        <Link
                            href="#"
                            onClick={(e) => {
                                e.preventDefault();
                                onSignUp();
                            }}
                        >
                            Sign up
                        </Link>
                    </Text>
                </Card.Footer>
            )}
        </Card>
    );
}

