import React, { useMemo } from 'react';

import { cn } from '@ds0/primitives';

import { Card } from '../../components/react/card';
import { Stack } from '../../components/react/stack';
import { Heading } from '../../components/react/heading';
import { Text } from '../../components/react/text';
import { Switch } from '../../components/react/switch';
import { Divider } from '../../components/react/divider';
import { Button } from '../../components/react/button';

/**
 * A single notification setting.
 */
interface NotificationSetting {
    id: string;
    category: string;
    label: string;
    description: string;
    enabled: boolean;
}

/**
 * Props for the NotificationSettings recipe component.
 */
interface NotificationSettingsProps {
    /** Current notification settings */
    settings: NotificationSetting[];
    /** Toggle handler */
    onSettingChange: (id: string, enabled: boolean) => void;
    /** Save all handler */
    onSave?: () => void | Promise<void>;
    /** Loading state */
    isLoading?: boolean;
    /** Additional CSS classes */
    className?: string;
}

/**
 * NotificationSettings recipe.
 * A notification preferences panel with categorized toggle switches.
 *
 * @example
 * ```tsx
 * <NotificationSettings
 *   settings={[
 *     { id: '1', category: 'Email', label: 'Marketing', description: 'Receive marketing emails', enabled: true },
 *   ]}
 *   onSettingChange={(id, enabled) => updateSetting(id, enabled)}
 * />
 * ```
 */
function NotificationSettings({
    settings,
    onSettingChange,
    onSave,
    isLoading = false,
    className,
}: NotificationSettingsProps): React.ReactElement {
    const categories = useMemo(() => {
        const grouped = new Map<string, NotificationSetting[]>();
        for (const setting of settings) {
            const group = grouped.get(setting.category) ?? [];
            group.push(setting);
            grouped.set(setting.category, group);
        }
        return Array.from(grouped.entries());
    }, [settings]);

    return (
        <Card className={cn('w-full max-w-2xl', className)}>
            <Card.Header>
                <Card.Title>Notifications</Card.Title>
                <Card.Description>Choose what notifications you want to receive.</Card.Description>
            </Card.Header>
            <Card.Content>
                <Stack gap="6">
                    {categories.map(([category, items], index) => (
                        <div key={category}>
                            {index > 0 && <Divider className="mb-6" />}
                            <Stack gap="4">
                                <Heading as="h4" size="sm" weight="semibold">
                                    {category}
                                </Heading>
                                {items.map((setting) => (
                                    <Switch
                                        key={setting.id}
                                        label={setting.label}
                                        description={setting.description}
                                        checked={setting.enabled}
                                        onCheckedChange={(checked) =>
                                            onSettingChange(setting.id, checked)
                                        }
                                    />
                                ))}
                            </Stack>
                        </div>
                    ))}

                    {onSave && (
                        <Stack direction="horizontal" justify="end">
                            <Button onClick={onSave} isLoading={isLoading}>
                                Save preferences
                            </Button>
                        </Stack>
                    )}
                </Stack>
            </Card.Content>
        </Card>
    );
}

NotificationSettings.displayName = 'NotificationSettings';

export { NotificationSettings };
export type { NotificationSettingsProps, NotificationSetting };

import React, { useState } from 'react';

import { cn } from '@ds0/primitives';

import { Card } from '../../components/react/card';
import { Stack } from '../../components/react/stack';
import { Heading } from '../../components/react/heading';
import { Text } from '../../components/react/text';
import { Button } from '../../components/react/button';
import { Badge } from '../../components/react/badge';
import { Divider } from '../../components/react/divider';

/**
 * A single pricing feature item.
 */
interface PricingFeature {
    label: string;
    included: boolean;
}

/**
 * A pricing tier.
 */
interface PricingTier {
    /** Tier name */
    name: string;
    /** Description */
    description?: string;
    /** Monthly price (number or 'Custom') */
    priceMonthly: number | string;
    /** Yearly price (number or 'Custom') */
    priceYearly?: number | string;
    /** Currency symbol */
    currency?: string;
    /** CTA button label */
    ctaLabel?: string;
    /** CTA handler */
    onSelect: () => void;
    /** Whether this is the highlighted/recommended tier */
    featured?: boolean;
    /** Badge text (e.g., 'Most popular') */
    badge?: string;
    /** Feature list */
    features: PricingFeature[];
}

/**
 * Props for the PricingCards recipe component.
 */
interface PricingCardsProps {
    /** Pricing tiers */
    tiers: PricingTier[];
    /** Show billing period toggle */
    showBillingToggle?: boolean;
    /** Additional CSS classes */
    className?: string;
}

/**
 * Check icon for included features.
 */
function CheckIcon(): React.ReactElement {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" className="text-green-600 shrink-0">
            <polyline points="20 6 9 17 4 12" />
        </svg>
    );
}

/**
 * X icon for excluded features.
 */
function XIcon(): React.ReactElement {
    return (
        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true" className="text-muted-foreground/50 shrink-0">
            <path d="M18 6 6 18" /><path d="m6 6 12 12" />
        </svg>
    );
}

/**
 * PricingCards recipe.
 * Marketing pricing section with tier cards, feature comparison, and billing toggle.
 *
 * @example
 * ```tsx
 * <PricingCards
 *   tiers={[
 *     { name: 'Free', priceMonthly: 0, features: [...], onSelect: () => {} },
 *     { name: 'Pro', priceMonthly: 29, features: [...], onSelect: () => {}, featured: true },
 *   ]}
 * />
 * ```
 */
function PricingCards({
    tiers,
    showBillingToggle = true,
    className,
}: PricingCardsProps): React.ReactElement {
    const [billingPeriod, setBillingPeriod] = useState<'monthly' | 'yearly'>('monthly');
    const hasYearlyPrices = tiers.some((t) => t.priceYearly !== undefined);

    const formatPrice = (price: number | string, currency = '$'): string => {
        if (typeof price === 'string') return price;
        if (price === 0) return 'Free';
        return `${currency}${price}`;
    };

    return (
        <Stack gap="8" align="center" className={className}>
            {/* Billing period toggle */}
            {showBillingToggle && hasYearlyPrices && (
                <div className="inline-flex items-center gap-2 rounded-full bg-muted p-1">
                    <button
                        type="button"
                        className={cn(
                            'rounded-full px-4 py-2 text-sm font-medium transition-colors',
                            billingPeriod === 'monthly' ? 'bg-background shadow-sm text-foreground' : 'text-muted-foreground hover:text-foreground',
                        )}
                        onClick={() => setBillingPeriod('monthly')}
                    >
                        Monthly
                    </button>
                    <button
                        type="button"
                        className={cn(
                            'rounded-full px-4 py-2 text-sm font-medium transition-colors',
                            billingPeriod === 'yearly' ? 'bg-background shadow-sm text-foreground' : 'text-muted-foreground hover:text-foreground',
                        )}
                        onClick={() => setBillingPeriod('yearly')}
                    >
                        Yearly
                    </button>
                </div>
            )}

            {/* Tier Cards */}
            <div className={cn('grid gap-6 w-full', tiers.length <= 3 ? `grid-cols-1 md:grid-cols-${tiers.length}` : 'grid-cols-1 md:grid-cols-2 lg:grid-cols-4')}>
                {tiers.map((tier) => {
                    const price = billingPeriod === 'yearly' && tier.priceYearly !== undefined
                        ? tier.priceYearly
                        : tier.priceMonthly;

                    return (
                        <Card
                            key={tier.name}
                            className={cn(
                                'relative flex flex-col',
                                tier.featured && 'border-primary shadow-lg scale-[1.02]',
                            )}
                        >
                            {tier.badge && (
                                <div className="absolute -top-3 left-1/2 -translate-x-1/2">
                                    <Badge>{tier.badge}</Badge>
                                </div>
                            )}
                            <Card.Header className="text-center">
                                <Card.Title>{tier.name}</Card.Title>
                                {tier.description && (
                                    <Card.Description>{tier.description}</Card.Description>
                                )}
                            </Card.Header>
                            <Card.Content className="flex-1">
                                <Stack gap="6">
                                    {/* Price */}
                                    <div className="text-center">
                                        <Heading as="h3" size="4xl" tracking="tight">
                                            {formatPrice(price, tier.currency)}
                                        </Heading>
                                        {typeof price === 'number' && price > 0 && (
                                            <Text size="sm" color="muted">
                                                per {billingPeriod === 'yearly' ? 'year' : 'month'}
                                            </Text>
                                        )}
                                    </div>

                                    <Divider />

                                    {/* Features */}
                                    <Stack gap="3">
                                        {tier.features.map((feature) => (
                                            <Stack
                                                key={feature.label}
                                                direction="horizontal"
                                                gap="3"
                                                align="center"
                                            >
                                                {feature.included ? <CheckIcon /> : <XIcon />}
                                                <Text
                                                    size="sm"
                                                    color={feature.included ? 'default' : 'muted'}
                                                >
                                                    {feature.label}
                                                </Text>
                                            </Stack>
                                        ))}
                                    </Stack>
                                </Stack>
                            </Card.Content>
                            <Card.Footer>
                                <Button
                                    className="w-full"
                                    variant={tier.featured ? 'default' : 'outline'}
                                    onClick={tier.onSelect}
                                >
                                    {tier.ctaLabel ?? 'Get started'}
                                </Button>
                            </Card.Footer>
                        </Card>
                    );
                })}
            </div>
        </Stack>
    );
}

PricingCards.displayName = 'PricingCards';

export { PricingCards };
export type { PricingCardsProps, PricingTier, PricingFeature };

import React, { useState, useRef } from 'react';

import { cn } from '@ds0/primitives';

import { Card } from '../../components/react/card';
import { Stack } from '../../components/react/stack';
import { Text } from '../../components/react/text';
import { Button } from '../../components/react/button';
import { Alert } from '../../components/react/alert';
import { TextField } from '../../components/react/text-field';
import { Avatar } from '../../components/react/avatar';
import { Divider } from '../../components/react/divider';

/**
 * Profile data for the ProfileSettings recipe.
 */
interface ProfileData {
    name: string;
    email: string;
    bio?: string;
    avatarUrl?: string;
}

/**
 * Props for the ProfileSettings recipe component.
 */
interface ProfileSettingsProps {
    /** Current profile data */
    initialValues: ProfileData;
    /** Save handler */
    onSubmit: (data: ProfileData) => void | Promise<void>;
    /** Cancel handler */
    onCancel?: () => void;
    /** Avatar upload handler */
    onAvatarChange?: (file: File) => void | Promise<string>;
    /** Loading state */
    isLoading?: boolean;
    /** Error message */
    error?: string;
    /** Additional CSS classes */
    className?: string;
}

/**
 * ProfileSettings recipe.
 * A profile editing form with avatar upload, name, email, bio, and save/cancel actions.
 *
 * @example
 * ```tsx
 * <ProfileSettings
 *   initialValues={{ name: 'John Doe', email: 'john@example.com' }}
 *   onSubmit={(data) => updateProfile(data)}
 * />
 * ```
 */
function ProfileSettings({
    initialValues,
    onSubmit,
    onCancel,
    onAvatarChange,
    isLoading = false,
    error,
    className,
}: ProfileSettingsProps): React.ReactElement {
    const [name, setName] = useState(initialValues.name);
    const [email, setEmail] = useState(initialValues.email);
    const [bio, setBio] = useState(initialValues.bio ?? '');
    const [avatarUrl, setAvatarUrl] = useState(initialValues.avatarUrl);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const handleSubmit = (e: React.FormEvent): void => {
        e.preventDefault();
        onSubmit({ name, email, bio, avatarUrl });
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>): void => {
        const file = e.target.files?.[0];
        if (file && onAvatarChange) {
            const result = onAvatarChange(file);
            if (result instanceof Promise) {
                result.then((url) => {
                    if (url) setAvatarUrl(url);
                });
            }
        }
    };

    return (
        <Card className={cn('w-full max-w-2xl', className)}>
            <Card.Header>
                <Card.Title>Profile</Card.Title>
                <Card.Description>Manage your public profile information.</Card.Description>
            </Card.Header>
            <Card.Content>
                <form onSubmit={handleSubmit}>
                    <Stack gap="6">
                        {error && (
                            <Alert variant="destructive">
                                <Alert.Description>{error}</Alert.Description>
                            </Alert>
                        )}

                        {/* Avatar Section */}
                        <Stack direction="horizontal" gap="6" align="center">
                            <Avatar
                                src={avatarUrl}
                                alt={initialValues.name}
                                size="xl"
                            />
                            {onAvatarChange && (
                                <Stack gap="2">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        type="button"
                                        onClick={() => fileInputRef.current?.click()}
                                    >
                                        Change avatar
                                    </Button>
                                    <Text size="xs" color="muted">JPG, PNG, or GIF. Max 2MB.</Text>
                                    <input
                                        ref={fileInputRef}
                                        type="file"
                                        accept="image/*"
                                        className="sr-only"
                                        onChange={handleFileChange}
                                        aria-label="Upload avatar"
                                    />
                                </Stack>
                            )}
                        </Stack>

                        <Divider />

                        <TextField
                            label="Full name"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            isRequired
                        />

                        <TextField
                            label="Email"
                            type="email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            isRequired
                        />

                        <div>
                            <TextField
                                label="Bio"
                                value={bio}
                                onChange={(e) => setBio(e.target.value)}
                                helperText="Brief description for your profile. Max 160 characters."
                            />
                            <Text size="xs" color="muted" align="right" className="mt-1">
                                {bio.length}/160
                            </Text>
                        </div>

                        <Stack direction="horizontal" gap="3" justify="end">
                            {onCancel && (
                                <Button variant="ghost" type="button" onClick={onCancel}>
                                    Cancel
                                </Button>
                            )}
                            <Button type="submit" isLoading={isLoading}>
                                Save changes
                            </Button>
                        </Stack>
                    </Stack>
                </form>
            </Card.Content>
        </Card>
    );
}

ProfileSettings.displayName = 'ProfileSettings';

export { ProfileSettings };
export type { ProfileSettingsProps, ProfileData };

import React, { useState } from 'react';

import { cn } from '@ds0/primitives';

import { Stack } from '../../components/react/stack';
import { Text } from '../../components/react/text';
import { Button } from '../../components/react/button';
import { Divider } from '../../components/react/divider';
import { Avatar } from '../../components/react/avatar';
import { Badge } from '../../components/react/badge';
import { Link } from '../../components/react/link';
import { Tooltip } from '../../components/react/tooltip';

/**
 * A navigation item.
 */
interface NavItem {
    label: string;
    href: string;
    icon?: React.ReactNode;
    badge?: string | number;
    children?: NavItem[];
    disabled?: boolean;
}

/**
 * A group of navigation items.
 */
interface NavGroup {
    label?: string;
    items: NavItem[];
}

/**
 * Props for the SidebarNavigation recipe component.
 */
interface SidebarNavigationProps {
    /** Navigation groups */
    groups: NavGroup[];
    /** Currently active path */
    currentPath: string;
    /** Header content (avatar, name, etc.) */
    header?: React.ReactNode;
    /** Footer content (settings link, logout, etc.) */
    footer?: React.ReactNode;
    /** Whether the sidebar is collapsed to icons only */
    collapsed?: boolean;
    /** Additional CSS classes */
    className?: string;
}

/**
 * Chevron icon for expandable items.
 */
function ChevronIcon({ open }: { open: boolean }): React.ReactElement {
    return (
        <svg
            xmlns="http://www.w3.org/2000/svg"
            width="16"
            height="16"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
            aria-hidden="true"
            className={cn('transition-transform', open && 'rotate-90')}
        >
            <polyline points="9 18 15 12 9 6" />
        </svg>
    );
}

/**
 * Individual nav item renderer.
 */
function NavItemRow({
    item,
    currentPath,
    collapsed,
    depth = 0,
}: {
    item: NavItem;
    currentPath: string;
    collapsed?: boolean;
    depth?: number;
}): React.ReactElement {
    const [expanded, setExpanded] = useState(
        item.children?.some((child) => child.href === currentPath) ?? false,
    );
    const isActive = item.href === currentPath;
    const hasChildren = item.children && item.children.length > 0;

    const content = (
        <a
            href={item.href}
            aria-current={isActive ? 'page' : undefined}
            aria-disabled={item.disabled}
            className={cn(
                'flex items-center gap-3 rounded-md px-3 py-2 text-sm font-medium transition-colors',
                'hover:bg-accent hover:text-accent-foreground',
                'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring',
                isActive && 'bg-accent text-accent-foreground',
                item.disabled && 'opacity-50 pointer-events-none',
                depth > 0 && 'ml-6',
            )}
            onClick={
                hasChildren
                    ? (e) => {
                        e.preventDefault();
                        setExpanded(!expanded);
                    }
                    : undefined
            }
        >
            {item.icon && <span className="shrink-0">{item.icon}</span>}
            {!collapsed && (
                <>
                    <span className="flex-1 truncate">{item.label}</span>
                    {item.badge !== undefined && (
                        <Badge variant="secondary" size="sm">
                            {item.badge}
                        </Badge>
                    )}
                    {hasChildren && <ChevronIcon open={expanded} />}
                </>
            )}
        </a>
    );

    return (
        <div>
            {collapsed && item.icon ? (
                <Tooltip content={item.label} side="right">
                    {content}
                </Tooltip>
            ) : (
                content
            )}
            {hasChildren && expanded && !collapsed && (
                <div className="mt-1">
                    {item.children!.map((child) => (
                        <NavItemRow
                            key={child.href}
                            item={child}
                            currentPath={currentPath}
                            collapsed={collapsed}
                            depth={depth + 1}
                        />
                    ))}
                </div>
            )}
        </div>
    );
}

/**
 * SidebarNavigation recipe.
 * A vertical navigation sidebar with grouped links, collapsible sections,
 * and active state indication.
 *
 * @example
 * ```tsx
 * <SidebarNavigation
 *   groups={[{ label: 'Main', items: [{ label: 'Dashboard', href: '/', icon: <HomeIcon /> }] }]}
 *   currentPath="/"
 * />
 * ```
 */
function SidebarNavigation({
    groups,
    currentPath,
    header,
    footer,
    collapsed = false,
    className,
}: SidebarNavigationProps): React.ReactElement {
    return (
        <nav
            className={cn(
                'flex h-full flex-col border-r bg-card',
                collapsed ? 'w-16' : 'w-64',
                'transition-all duration-200',
                className,
            )}
            aria-label="Sidebar navigation"
        >
            {header && (
                <>
                    <div className="p-4">{header}</div>
                    <Divider />
                </>
            )}

            <div className="flex-1 overflow-y-auto p-3">
                <Stack gap="6">
                    {groups.map((group, index) => (
                        <div key={group.label ?? index}>
                            {group.label && !collapsed && (
                                <Text
                                    as="span"
                                    size="xs"
                                    weight="semibold"
                                    color="muted"
                                    className="mb-2 block px-3 uppercase tracking-wider"
                                >
                                    {group.label}
                                </Text>
                            )}
                            <Stack gap="1">
                                {group.items.map((item) => (
                                    <NavItemRow
                                        key={item.href}
                                        item={item}
                                        currentPath={currentPath}
                                        collapsed={collapsed}
                                    />
                                ))}
                            </Stack>
                        </div>
                    ))}
                </Stack>
            </div>

            {footer && (
                <>
                    <Divider />
                    <div className="p-4">{footer}</div>
                </>
            )}
        </nav>
    );
}

SidebarNavigation.displayName = 'SidebarNavigation';

export { SidebarNavigation };
export type { SidebarNavigationProps, NavGroup, NavItem };

import React, { useState } from 'react';

import { cn } from '@ds0/primitives';

import { Card } from '../../components/react/card';
import { Stack } from '../../components/react/stack';
import { Text } from '../../components/react/text';
import { Button } from '../../components/react/button';
import { Alert } from '../../components/react/alert';
import { TextField } from '../../components/react/text-field';
import { Checkbox } from '../../components/react/checkbox';
import { Link } from '../../components/react/link';
import { Divider } from '../../components/react/divider';

/**
 * Props for the SignupForm recipe component.
 */
interface SignupFormProps {
    /** Form submission handler */
    onSubmit: (data: { name: string; email: string; password: string }) => void | Promise<void>;
    /** Switch to login handler */
    onLogin?: () => void;
    /** Social signup handler */
    onSocialSignup?: (provider: string) => void;
    /** Social providers */
    socialProviders?: Array<{ name: string; icon: React.ReactNode }>;
    /** Card title */
    title?: string;
    /** Card description */
    description?: string;
    /** Loading state */
    isLoading?: boolean;
    /** Form-level error */
    error?: string;
    /** Terms of service URL (shows checkbox when provided) */
    termsUrl?: string;
    /** Privacy policy URL */
    privacyUrl?: string;
    /** Password requirements shown below password field */
    passwordRequirements?: string[];
    /** Additional CSS classes */
    className?: string;
}

/**
 * SignupForm recipe.
 * A complete registration form with name, email, password, password confirmation,
 * terms agreement, and optional social signup.
 *
 * @example
 * ```tsx
 * <SignupForm
 *   onSubmit={({ name, email, password }) => register(name, email, password)}
 *   onLogin={() => navigate('/login')}
 *   termsUrl="/terms"
 *   privacyUrl="/privacy"
 * />
 * ```
 */
function SignupForm({
    onSubmit,
    onLogin,
    onSocialSignup,
    socialProviders,
    title = 'Create an account',
    description = 'Get started in seconds',
    isLoading = false,
    error,
    termsUrl,
    privacyUrl,
    passwordRequirements,
    className,
}: SignupFormProps): React.ReactElement {
    const [name, setName] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [confirmPassword, setConfirmPassword] = useState('');
    const [termsAccepted, setTermsAccepted] = useState(false);
    const [passwordError, setPasswordError] = useState('');

    const handleSubmit = (e: React.FormEvent): void => {
        e.preventDefault();
        if (password !== confirmPassword) {
            setPasswordError('Passwords do not match');
            return;
        }
        setPasswordError('');
        onSubmit({ name, email, password });
    };

    return (
        <Card className={cn('w-full max-w-md', className)}>
            <Card.Header>
                <Card.Title>{title}</Card.Title>
                <Card.Description>{description}</Card.Description>
            </Card.Header>
            <Card.Content>
                <Stack gap="6">
                    {/* Social Signup */}
                    {socialProviders && socialProviders.length > 0 && onSocialSignup && (
                        <>
                            <Stack gap="3">
                                {socialProviders.map((provider) => (
                                    <Button
                                        key={provider.name}
                                        variant="outline"
                                        className="w-full"
                                        leftIcon={provider.icon}
                                        onClick={() => onSocialSignup(provider.name)}
                                    >
                                        Continue with {provider.name}
                                    </Button>
                                ))}
                            </Stack>

                            <div className="relative">
                                <Divider />
                                <Text
                                    as="span"
                                    size="xs"
                                    color="muted"
                                    className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 bg-card px-2"
                                >
                                    or continue with email
                                </Text>
                            </div>
                        </>
                    )}

                    {/* Error */}
                    {error && (
                        <Alert variant="destructive">
                            <Alert.Description>{error}</Alert.Description>
                        </Alert>
                    )}

                    {/* Form */}
                    <form onSubmit={handleSubmit}>
                        <Stack gap="4">
                            <TextField
                                label="Full name"
                                type="text"
                                placeholder="John Doe"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                autoComplete="name"
                                isRequired
                            />

                            <TextField
                                label="Email"
                                type="email"
                                placeholder="you@example.com"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                autoComplete="email"
                                isRequired
                            />

                            <div>
                                <TextField
                                    label="Password"
                                    type="password"
                                    placeholder="••••••••"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    autoComplete="new-password"
                                    isRequired
                                />
                                {passwordRequirements && passwordRequirements.length > 0 && (
                                    <ul className="mt-1.5 space-y-1">
                                        {passwordRequirements.map((req) => (
                                            <li key={req} className="text-xs text-muted-foreground">
                                                • {req}
                                            </li>
                                        ))}
                                    </ul>
                                )}
                            </div>

                            <TextField
                                label="Confirm password"
                                type="password"
                                placeholder="••••••••"
                                value={confirmPassword}
                                onChange={(e) => setConfirmPassword(e.target.value)}
                                autoComplete="new-password"
                                isInvalid={!!passwordError}
                                errorMessage={passwordError}
                                isRequired
                            />

                            {termsUrl && (
                                <Checkbox
                                    label={
                                        <Text as="span" size="sm">
                                            I agree to the{' '}
                                            <Link href={termsUrl} isExternal size="sm">Terms of Service</Link>
                                            {privacyUrl && (
                                                <>
                                                    {' '}and{' '}
                                                    <Link href={privacyUrl} isExternal size="sm">Privacy Policy</Link>
                                                </>
                                            )}
                                        </Text>
                                    }
                                    checked={termsAccepted}
                                    onCheckedChange={(checked) => setTermsAccepted(checked === true)}
                                />
                            )}

                            <Button type="submit" className="w-full" isLoading={isLoading}>
                                Create account
                            </Button>
                        </Stack>
                    </form>
                </Stack>
            </Card.Content>

            {onLogin && (
                <Card.Footer className="justify-center">
                    <Text size="sm" color="muted" as="span">
                        Already have an account?{' '}
                        <Link
                            href="#"
                            onClick={(e) => {
                                e.preventDefault();
                                onLogin();
                            }}
                        >
                            Sign in
                        </Link>
                    </Text>
                </Card.Footer>
            )}
        </Card>
    );
}

SignupForm.displayName = 'SignupForm';

export { SignupForm };
export type { SignupFormProps };
